UPDATE tour_product_pages AS p
SET detail_payload = jsonb_set(p.detail_payload, '{pickup_dropoff}', CASE
  WHEN p.slug IN ('jeju-grand-highlights-loop', 'jeju-eastern-unesco-spots-day-tour', 'jeju-west-south-full-day-authentic-tour', 'jeju-southern-top-unesco-spots-tour', 'jeju-winter-southwest-tangerine-snow-camellia-tour', 'jeju-hydrangea-festival-tour-east-route', 'jeju-hydrangea-festival-tour-southwest-route', 'jeju-cherry-blossom-tour-east-route', 'jeju-cruise-shore-excursion-bus-tour', 'jeju-cruise-shore-excursion-small-group-tour') THEN '{"departure":[{"order":1,"time":"08:30","name":"オーシャンスイーツ済州ホテル","type":"hotel","note":"ホテルロビーでお待ちください。ガイドはAtoCKoreaのサインを持っています。","lat":33.4944,"lng":126.4808},{"order":2,"time":"08:45","name":"済州国際空港（3F 3番ゲート）","type":"airport","note":"3階出発エリア。3番ゲートの案内板に従ってください。","lat":33.5108,"lng":126.4932},{"order":3,"time":"08:55","name":"ロッテシティホテル済州","type":"hotel","note":"メインロビーでお待ちください。ガイドがお名前をお呼びします。","lat":33.4963,"lng":126.4865},{"order":4,"time":"09:05","name":"新羅免税店 済州店","type":"shopping","note":"新羅免税店済州店のメインエントランス前でお会いしましょう。","lat":33.4958,"lng":126.5252}],"return":[{"order":1,"name":"オーシャンスイーツ済州ホテル","type":"hotel","lat":33.4944,"lng":126.4808},{"order":2,"name":"済州国際空港（3F 3番ゲート）","type":"airport","lat":33.5108,"lng":126.4932},{"order":3,"name":"ロッテシティホテル済州","type":"hotel","lat":33.4963,"lng":126.4865},{"order":4,"name":"新羅免税店 済州店","type":"shopping","lat":33.4958,"lng":126.5252},{"order":5,"name":"東門在来市場","type":"market","lat":33.5136,"lng":126.5296}],"notes":["帰着は通常17:30〜18:00頃となります。"]}'::jsonb
  WHEN p.slug = 'busan-top-attractions-day-tour' THEN '{"departure":[{"order":1,"time":"08:30","name":"西面駅 4番出口","type":"station","lat":35.1577,"lng":129.0592},{"order":2,"time":"08:50","name":"Busan Station Exit 4 (not the KTX gate)","type":"station","lat":35.1152,"lng":129.0421},{"order":3,"time":"09:30","name":"海雲台駅 5番出口","type":"station","lat":35.1628,"lng":129.1603}],"return":[{"order":1,"name":"南浦洞 / チャガルチ","type":"station","lat":35.0978,"lng":129.0286},{"order":2,"name":"釜山駅 4番出口","type":"station","lat":35.1152,"lng":129.0421},{"order":3,"name":"西面駅 4番出口","type":"station","lat":35.1577,"lng":129.0592},{"order":4,"name":"海雲台駅 5番出口","type":"station","lat":35.1628,"lng":129.1603}],"notes":["Choose the pickup exit closest to your hotel at booking. Drop-offs are sequential along the return route; passengers boarding at Seomyeon (08:30) experience the longest day (≈10 hours), Haeundae passengers the shortest (≈9.5 hours)."]}'::jsonb
  WHEN p.slug = 'busan-small-group-sightseeing-tour-cruise-passengers' THEN '{"departure":[{"order":1,"time":"Planned to ship disembarkation","name":"釜山港国際旅客ターミナル","type":"station","lat":35.1067,"lng":129.0365}],"return":[{"order":1,"name":"釜山港国際旅客ターミナル","type":"station","lat":35.1067,"lng":129.0365}],"notes":["Provide ship name, port-call date, expected disembarkation time, and all-aboard time at booking. Shared van with other cruise passengers from various ships. Early pickup (before 08:00) adds ₩10,000 per person to compensate the guide for the early start."]}'::jsonb
  WHEN p.slug = 'busan-gyeongju-unesco-legacy-tour-national-museum' THEN '{"departure":[{"order":1,"time":"08:10","name":"釜山駅 4番出口","type":"station","lat":35.1152,"lng":129.0421},{"order":2,"time":"08:30","name":"西面駅 4番出口","type":"station","lat":35.1577,"lng":129.0592},{"order":3,"time":"09:10","name":"海雲台駅 5番出口","type":"station","lat":35.1628,"lng":129.1603}],"return":[{"order":1,"name":"海雲台駅 5番出口","type":"station","lat":35.1628,"lng":129.1603},{"order":2,"name":"西面駅 4番出口","type":"station","lat":35.1577,"lng":129.0592},{"order":3,"name":"釜山駅 4番出口","type":"station","lat":35.1152,"lng":129.0421}],"notes":["Choose the pickup exit closest to your hotel at booking. Year-round itinerary; cherry-blossom season (typically mid-March to mid-April) swaps Ahopsan Bamboo Forest for Haeundae Dalmaji Hill."]}'::jsonb
  WHEN p.slug = 'busan-plum-cherry-blossom-day-tour-to-yangsan-gyeongju' THEN '{"departure":[{"order":1,"time":"08:00","name":"釜山駅（KTX メイン出口）","type":"station","note":"Group meeting point at the main exit; staff with AtoC Korea sign.","lat":35.1152,"lng":129.0421},{"order":2,"time":"08:15","name":"西面駅 7番出口","type":"station","note":"Second pickup point on the way out of central Busan.","lat":35.1577,"lng":129.0592},{"order":3,"time":"08:30","name":"老圃駅 3番出口","type":"station","note":"Third pickup — Nopo is the closest Busan subway station to Tongdosa (~25 min drive), so this point fits the Yangsan-first day.","lat":35.2285,"lng":129.0784}],"return":[{"order":1,"name":"同じ3つの駅（逆順）","type":"station","note":"Drop-off at any of the three pickup stations on request; total tour ~8.5 hours from Busan Station pickup to Busan Station drop-off."}],"notes":["This tour operates ONLY during the spring blossom window — approximately Feb 25 to Apr 10, 2026. It is a DUAL-SEASON product: plum blossom (매화, peak ~Mar 1–15 at Tongdosa Jajangmae and Yangsan Wondong) blends into cherry blossom (벚꽃, peak ~Mar 28–Apr 10 at Bulguksa and Bomun Lake). Daily route is adjusted by season: early dates emphasize Yangsan (Tongdosa + Wondong); later dates pivot to Gyeongju (Bulguksa + Bomun Lake). Mid-season days cover both. Departure is a fixed group shuttle (small_group product) so pickup times are not flexible. Lunch is at own expense (~10,000–20,000 KRW); during plum season the recommended lunch is Wondong''s Minari Samgyeopsal (clean-water parsley grilled with pork belly, only available this season). Wheelchair and stroller travelers — please notify at booking; Tongdosa has a 1.2 km riverside walk and gentle slopes, Bulguksa has stairs."]}'::jsonb
  WHEN p.slug = 'busan-spring-cherry-blossom-gyeongju-highlights-day-tour' THEN '{"departure":[{"order":1,"time":"08:00","name":"釜山駅（KTX メイン出口）","type":"station","note":"Group meeting point at the main exit; staff with AtoC Korea sign.","lat":35.1152,"lng":129.0421},{"order":2,"time":"08:15","name":"西面駅 7番出口","type":"station","note":"Second pickup point on the way out of central Busan.","lat":35.1577,"lng":129.0592},{"order":3,"time":"08:30","name":"海雲台駅 5番出口","type":"station","note":"Third pickup point for guests staying in Haeundae.","lat":35.1628,"lng":129.1603}],"return":[{"order":1,"name":"同じ3つの駅（逆順）","type":"station","note":"Drop-off at any of the three pickup stations on request; total tour ~8.5 hours from Busan Station pickup to Busan Station drop-off."}],"notes":["This tour operates ONLY during cherry blossom season (approximately March 28 to April 10, 2026 — exact dates depend on bloom forecast and confirmed annually). Departure is a fixed group shuttle (small_group product) so pickup times are not flexible. If bloom is delayed or finished, the tour may be cancelled with 3 days'' notice and full refund. Lunch is at own expense (~10,000–20,000 KRW) at a Gyeongju local restaurant chosen by the guide based on the day''s route. Wheelchair and stroller travelers — please notify at booking; some stops involve uneven ground (Bulguksa stairs, grass paths at Daereungwon)."]}'::jsonb
  WHEN p.slug = 'from-busan-gyeongju-ancient-capital-day-tour' THEN '{"departure":[{"order":1,"time":"08:10","name":"釜山駅 4番出口","type":"station","lat":35.1152,"lng":129.0421},{"order":2,"time":"08:30","name":"西面駅 4番出口","type":"station","lat":35.1577,"lng":129.0592},{"order":3,"time":"09:10","name":"海雲台駅 5番出口","type":"station","lat":35.1628,"lng":129.1603}],"return":[{"order":1,"name":"海雲台駅 5番出口","type":"station","lat":35.1628,"lng":129.1603},{"order":2,"name":"西面駅 4番出口","type":"station","lat":35.1577,"lng":129.0592},{"order":3,"name":"釜山駅 4番出口","type":"station","lat":35.1152,"lng":129.0421}],"notes":["Same six-attraction route year-round (Bulguksa, museum, Gyochon, bridge, plus Ahopsan Bamboo Forest as morning opener). Cherry blossom season (mid-March to mid-April) swaps Ahopsan for Haeundae Dalmaji Hill. Choose the pickup exit closest to your hotel."]}'::jsonb
  WHEN p.slug = 'seoul-suwon-hwaseong-folk-village-starfield-library' THEN '{"departure":[{"order":1,"time":"08:00","name":"弘大入口駅 8番出口","type":"station","lat":37.5573,"lng":126.925},{"order":2,"time":"08:30","name":"明洞駅 2番または4番出口","type":"station","lat":37.5636,"lng":126.9847}],"return":[{"order":1,"name":"弘大入口駅 8番出口","type":"station","lat":37.5573,"lng":126.925},{"order":2,"name":"明洞駅 4番出口","type":"station","lat":37.5636,"lng":126.9847}],"notes":["Arrive 10 minutes early. Latecomers cannot be accommodated and are non-refundable."]}'::jsonb
  WHEN p.slug = 'seoul-suwon-hwaseong-gwangmyeong-cave-starfield-library' THEN '{"departure":[{"order":1,"time":"08:00","name":"弘大入口駅 8番出口","type":"station","lat":37.5573,"lng":126.925},{"order":2,"time":"08:30","name":"明洞駅 2番または4番出口","type":"station","lat":37.5636,"lng":126.9847}],"return":[{"order":1,"name":"弘大入口駅 8番出口","type":"station","lat":37.5573,"lng":126.925},{"order":2,"name":"明洞駅 4番出口","type":"station","lat":37.5636,"lng":126.9847}],"notes":["Arrive 10 minutes early. Latecomers cannot be accommodated and are non-refundable. Tour does not operate on Mondays (Gwangmyeong Cave closed)."]}'::jsonb
  WHEN p.slug = 'seoul-suwon-hwaseong-waujeongsa-starfield' THEN '{"departure":[{"order":1,"time":"08:30","name":"弘大入口駅 4番出口","type":"station","note":"First Seoul meeting point; please arrive 10 minutes early.","lat":37.5573,"lng":126.925},{"order":2,"time":"09:00","name":"明洞駅","type":"station","note":"Second Seoul meeting point.","lat":37.5636,"lng":126.9847}],"return":[{"order":1,"name":"明洞駅","type":"station","note":"Standard Seoul drop-off point.","lat":37.5636,"lng":126.9847},{"order":2,"name":"弘大入口駅","type":"station","note":"Standard Seoul drop-off point.","lat":37.5573,"lng":126.925}],"notes":["Return time depends on traffic and is typically between 18:00 and 19:00. Drop-off order may be adjusted slightly for operational efficiency. Please arrive at least 10 minutes early at your selected meeting point. This is a fixed-meeting-point format, not hotel pickup."]}'::jsonb
  WHEN p.slug = 'seoul-seoraksan-national-park-sokcho-beach-day-trip' THEN '{"departure":[{"order":1,"time":"07:00","name":"弘大入口駅 8番出口","type":"station","lat":37.5573,"lng":126.925},{"order":2,"time":"07:30","name":"明洞駅 4番出口","type":"station","lat":37.5636,"lng":126.9847}],"return":[{"order":1,"name":"弘大入口駅 8番出口","type":"station","lat":37.5573,"lng":126.925},{"order":2,"name":"明洞駅 4番出口","type":"station","lat":37.5636,"lng":126.9847}],"notes":["Arrive 10 minutes early. Latecomers cannot be accommodated and are non-refundable."]}'::jsonb
  WHEN p.slug = 'from-incheon-seoul-day-tour-cruise-guests' THEN '{"departure":[{"order":1,"time":"Calibrated to ship disembarkation","name":"仁川港国際旅客ターミナル（松島）","type":"station","lat":37.4703,"lng":126.64}],"return":[{"order":1,"name":"仁川港国際旅客ターミナル","type":"station","lat":37.4703,"lng":126.64}],"notes":["Provide ship name, port-call date, expected disembarkation time, and all-aboard time at booking. Shared van with other cruise passengers from various ships. The guide tracks each passenger''s individual ship schedule; if multiple ships sail at different times, earliest-sailing passengers are dropped first."]}'::jsonb
  ELSE p.detail_payload -> 'pickup_dropoff'
END)
WHERE p.locale = 'ja' AND p.slug IN ('jeju-grand-highlights-loop', 'jeju-eastern-unesco-spots-day-tour', 'jeju-west-south-full-day-authentic-tour', 'jeju-southern-top-unesco-spots-tour', 'jeju-winter-southwest-tangerine-snow-camellia-tour', 'jeju-hydrangea-festival-tour-east-route', 'jeju-hydrangea-festival-tour-southwest-route', 'jeju-cherry-blossom-tour-east-route', 'jeju-cruise-shore-excursion-bus-tour', 'jeju-cruise-shore-excursion-small-group-tour', 'busan-top-attractions-day-tour', 'busan-small-group-sightseeing-tour-cruise-passengers', 'busan-gyeongju-unesco-legacy-tour-national-museum', 'busan-plum-cherry-blossom-day-tour-to-yangsan-gyeongju', 'busan-spring-cherry-blossom-gyeongju-highlights-day-tour', 'from-busan-gyeongju-ancient-capital-day-tour', 'seoul-suwon-hwaseong-folk-village-starfield-library', 'seoul-suwon-hwaseong-gwangmyeong-cave-starfield-library', 'seoul-suwon-hwaseong-waujeongsa-starfield', 'seoul-seoraksan-national-park-sokcho-beach-day-trip', 'from-incheon-seoul-day-tour-cruise-guests');